sql:
SELECT AVG(elo_rating) AS average_elo_rating
FROM elo_ratings
WHERE club_id = 1;

SELECT description
FROM club_achievements
WHERE club_id = 0 AND achievement_type = 'championship';

SELECT COUNT(*) AS win_count
  FROM club_stats
  WHERE club_id = 0 AND stat_type = 'wins';

SELECT MAX(elo_rating) AS max_elo_rating
FROM elo_ratings
WHERE rating_type = 'global';

SELECT COUNT(player_id) AS player_count
FROM club_players
WHERE club_id = 1;

SELECT goals
FROM club_players
WHERE player_id = 1;

SELECT club_name
FROM clubs
WHERE club_id = 1;

SELECT player_name, join_date
FROM club_players
WHERE goals > 10;

SELECT SUM(revenue) AS total_revenue
FROM club_finances
WHERE club_id = 0 AND season = '2022-2023';

SELECT profit
FROM club_finances
WHERE club_id = 0 AND season = '2022-2023';

external_knowledge:
- 'Exceptionally skilled' refers to an average Elo rating greater than 1500; 
- 'Prestigious cup competition' refers to an achievement type of 'cup win';
- 'Within the last five years' implies a date greater than or equal to five years ago from the current date.
